package com.google.gson;
import com.google.gson.internal.Streams;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.io.StringWriter;
import java.math.BigDecimal;
import java.math.BigInteger;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class JsonElementTest {

  static class JsonNullSubclass extends JsonNull {
    // Concrete subclass of JsonNull for testing
  }

  static class JsonElementMock extends JsonElement {
    @Override
    public JsonElement deepCopy() {
      return this;
    }
  }

  @Test
  void testIsJsonNull_whenInstanceIsJsonNull() {
    JsonElement jsonNull = new JsonNullSubclass();
    assertTrue(jsonNull.isJsonNull());
  }

  @Test
  void testIsJsonNull_whenInstanceIsNotJsonNull() {
    JsonElement element = new JsonElementMock();
    assertFalse(element.isJsonNull());
  }
}
